def compute_score() -> tuple[str, float]:
    import pptx
    from pptx import Presentation
    import re
    required_phrase = "These drawings show standardized proportional relationships"
    prs = pptx.Presentation(modified_ppt_path)
    slide7 = None
    for s in prs.slides:
        if getattr(s, 'slide_number', None) == 7 or prs.slides.index(s) == 6:
            slide7 = s
            break
    if slide7 is None:
        return ("Slide 7 not found in modified presentation.", 0.0)
    # Get all text from text boxes
    textbox_texts = [shape.text.strip() for shape in slide7.shapes if shape.has_text_frame]
    # Remove any text that existed in the original
    orig_prs = pptx.Presentation(original_ppt_path)
    orig_slide7 = None
    for s in orig_prs.slides:
        if getattr(s, 'slide_number', None) == 7 or orig_prs.slides.index(s) == 6:
            orig_slide7 = s
            break
    orig_texts = [shape.text.strip() for shape in orig_slide7.shapes if shape.has_text_frame] if orig_slide7 else []
    new_texts = [t for t in textbox_texts if t not in orig_texts]
    if not new_texts:
        return ("No new text box text found on slide 7.", 0.0)
    # Check for required phrase or paraphrase
    found = False
    for t in new_texts:
        # Fuzzy match (case insensitive, ignore minor punctuation)
        if required_phrase.lower() in t.lower():
            found = True
            break
        # Basic paraphrase detection
        if (re.search(r'standardized( proportional)? relationships', t, re.I) and re.search(r'drawing', t, re.I)):
            found = True
            break
    if not found:
        return ("No text box with required explanation found.", 0.0)
    # Check for extraneous unrelated content
    for t in new_texts:
        # If text is much longer than the required phrase, suspect extraneous content
        if len(t) > len(required_phrase)*2:
            return ("Text box contains excessive or unrelated information.", 0.5)
    return ("Text box contains the required explanation.", 1.0)

def compute_score() -> tuple[str, float]:
    import pptx
    from pptx import Presentation
    prs = pptx.Presentation(modified_ppt_path)
    slide7 = prs.slides[6] if len(prs.slides) >= 7 else None
    if slide7 is None:
        return ("Slide 7 not found in modified presentation.", 0.0)
    textbox_shapes = [shape for shape in slide7.shapes if shape.has_text_frame]
    orig_prs = pptx.Presentation(original_ppt_path)
    orig_slide7 = orig_prs.slides[6] if len(orig_prs.slides) >= 7 else None
    orig_text_shape_count = len([shape for shape in orig_slide7.shapes if shape.has_text_frame]) if orig_slide7 else 0
    new_textboxes = textbox_shapes[orig_text_shape_count:]
    if not new_textboxes:
        return ("No new text box found on slide 7.", 0.0)
    for shape in new_textboxes:
        # Check size and position
        left, top, width, height = shape.left, shape.top, shape.width, shape.height
        # PowerPoint slide size is usually 914400 x 685800 EMUs (10"x7.5")
        if width < 100000 or height < 40000:
            return ("Text box is too small to be visible.", 0.5)
        if left+width < 50000 or top+height < 50000:
            return ("Text box is off-slide or hidden.", 0.5)
        # If text is white on white bg, could be invisible (but python-pptx doesn't give bg color reliably)
        # We'll skip color check for now
    return ("Text box is clearly visible and reasonably formatted.", 1.0)
